/* ── RESET ── */
*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

:root {
    --brand-dark:  #011e3c;
    --brand-mid:   #0450a8;
    --brand-light: #1a6fd4;
    --text-primary:#0f172a;
    --text-muted:  #64748b;
    --border:      #e2e8f0;
    --surface:     #ffffff;
    --bg:          #f8fafc;
    --radius-sm:   8px;
    --radius-md:   14px;
    --radius-lg:   20px;
    --shadow-sm:   0 1px 4px rgba(0,0,0,0.07);
    --shadow-md:   0 4px 16px rgba(0,0,0,0.10);
    --nav-h:       68px;
}

body.homepage-body {
    font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
    background: var(--bg);
    color: var(--text-primary);
    min-height: 100vh;
    overflow-x: hidden;
    scrollbar-width: thin;
    scrollbar-color: #cbd5e1 transparent;
}

/* ════════════════════
   NAVBAR
   ════════════════════ */
.top-navbar {
    position: fixed;
    top: 0; left: 0; right: 0;
    z-index: 200;
    height: var(--nav-h);
    background: linear-gradient(135deg, #022a54 0%, #0450a8 60%, #0d5fc4 100%);
    box-shadow: 0 2px 16px rgba(2,42,84,0.35);
    border-bottom: 1px solid rgba(255,255,255,0.08);
}

.navbar-container {
    max-width: 1280px;
    margin: 0 auto;
    padding: 0 32px;
    height: 100%;
    display: flex;
    align-items: center;
}

.navbar-left {
    display: flex;
    align-items: center;
    gap: 10px;
    flex-shrink: 0;
    text-decoration: none;
}

