content.data:
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body.youth-dashboard {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: #f5f7fa;
    color: #333;
    overflow: hidden; /* Prevent body scroll */
    position: relative;
    height: 100vh;
}

/* Prevent any parallax or shake effects */
* {
    -webkit-backface-visibility: hidden;
    -moz-backface-visibility: hidden;
    -ms-backface-visibility: hidden;
    backface-visibility: hidden;
}

/* Top Navigation Bar - Completely Fixed */
.top-navbar {
    background: linear-gradient(135deg, #022a54 0%, #0450a8 50%, #0d5fc4 100%);
    box-shadow: 0 2px 12px rgba(4, 80, 168, 0.3);
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    width: 100%;
    z-index: 100;
    transform: none !important;
    overflow: visible;
}

.navbar-container {
    max-width: 1400px;
    margin: 0 auto;
    padding: 12px 24px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 24px;
}

.navbar-left {
    display: flex;
    align-items: center;
    gap: 12px;
}

.navbar-logo {
    width: 40px;
    height: 40px;
    object-fit: cover;
    border-radius: 50%;
    background: white;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
}

.navbar-title {
    font-size: 18px;
    font-weight: 700;
    color: white;
}

.navbar-center {
    flex: 1;
    max-width: 600px;
}

.search-bar {
    position: relative;
    width: 100%;
}

.search-icon {
    position: absolute;
    left: 14px;
    top: 50%;
    transform: translateY(-50%);
    width: 20px;
    height: 20px;
    color: #0450a8;
}

.search-input {
    width: 100%;
    padding: 10px 14px 10px 44px;
    border: 2px solid rgba(255, 255, 255, 0.3);
    border-radius: 24px;
    font-size: 14px;
    transition: all 0.3s ease;
    background: rgba(255, 255, 255, 0.95);
}

.search-input:focus {
    outline: none;
    border-color: white;
    background: white;
    box-shadow: 0 0 0 3px rgba(255, 255, 255, 0.2);
}

.search-input::placeholder {
    color: #999;
}

.navbar-right {
    display: flex;
    align-items: center;
    gap: 12px;
}

.nav-icon-btn {
    position: relative;
    width: 40px;
    height: 40px;
    border: none;
    background: rgba(255, 255, 255, 0.2);
    border-radius: 50%;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.3s ease;
}

.nav-icon-btn svg {
    width: 20px;
    height: 20px;

    color: white;
}

.nav-icon-btn:hover {
    background: rgba(255, 255, 255, 0.3);
}

.nav-icon-btn:hover svg {
    color: white;
}

.notification-badge {
    position: absolute;
    top: 4px;
    right: 4px;
    background: #f44336;
    color: white;
    font-size: 10px;
    font-weight: 700;
    padding: 2px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

/* User Menu */
.user-menu {
    position: relative;
}

.user-avatar-btn {
    width: 40px;
    height: 40px;
    border: 2px solid white;
    border-radius: 50%;
    cursor: pointer;
    background: none;
    padding: 0;
    overflow: hidden;
}

.user-avatar-btn img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.user-dropdown {
    position: absolute;
    top: calc(100% + 8px);
    right: 0;
    background: white;
    border-radius: 12px;
    box-shadow: 0 8px 24px rgba(0, 0, 0, 0.15);
    min-width: 240px;
    opacity: 0;
    visibility: hidden;
    transform: translateY(-10px);
    transition: all 0.3s ease;
}

.user-menu:hover .user-dropdown {
    opacity: 1;
    visibility: visible;
    transform: translateY(0);
}

.dropdown-header {
    padding: 16px;
    display: flex;
    align-items: center;
    gap: 12px;
}

.dropdown-header img {
    width: 48px;
    height: 48px;
    border-radius: 50%;
}

.user-name {
    font-weight: 600;
    font-size: 14px;
    color: #333;
    margin-bottom: 2px;
}

.user-email {
    font-size: 12px;
    color: #999;
}

.dropdown-divider {
    height: 1px;
    background: #e0e0e0;
    margin: 0 8px;
}

.dropdown-item {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 12px 16px;
    color: #666;
    text-decoration: none;
    font-size: 14px;
    transition: all 0.2s ease;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    cursor: pointer;
}

.dropdown-item svg {
    width: 18px;
    height: 18px;
}

.dropdown-item:hover {
    background: #f5f7fa;
    color: #667eea;
}

.logout-btn {
    color: #f44336;
}

.logout-btn:hover {
    background: #ffebee;
    color: #d32f2f;
}

/* Main Dashboard */
.dashboard-main {
    padding: 24px;
    padding-top: 88px;
    height: 100vh;
    overflow: hidden;
}

.dashboard-container {
    max-width: 1400px;
    margin: 0 auto;
    display: grid;
    grid-template-columns: 1fr 360px;
    gap: 24px;
    height: calc(100vh - 112px); /* Full height minus navbar and padding */
}

/* Feed Section - Independent Scroll */
.feed-section {
    display: flex;
    flex-direction: column;
    gap: 20px;
    overflow-y: auto;
    overflow-x: hidden;
    height: 100%;
    padding-right: 8px;
}

/* Custom Scrollbar for Feed */
.feed-section::-webkit-scrollbar {
    width: 8px;
}

.feed-section::-webkit-scrollbar-track {
    background: rgba(241, 241, 241, 0.5);
    border-radius: 10px;
}

.feed-section::-webkit-scrollbar-thumb {
    background: rgba(102, 126, 234, 0.3);
    border-radius: 10px;
}

.feed-section::-webkit-scrollbar-thumb:hover {
    background: rgba(102, 126, 234, 0.5);
}

.feed-header h1 {
    font-size: 28px;
    color: #333;
    margin-bottom: 4px;
}

.feed-header p {
    color: #999;
    font-size: 14px;
}

/* Post Card */
.post-card {
    background: white;
    border-radius: 16px;
    padding: 24px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
    transition: box-shadow 0.3s ease;
    will-change: auto;
    transform: translateZ(0);
}

.post-card:hover {
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);
}

.post-header {
    display: flex;
    align-items: center;
    gap: 12px;
    margin-bottom: 16px;
}

.post-avatar {
    width: 48px;
    height: 48px;
    border-radius: 50%;
    object-fit: cover;
}

.post-info {
    flex: 1;
}

.post-author {
    font-size: 16px;
    font-weight: 600;
    color: #333;
    margin-bottom: 4px;
}

.post-meta {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 13px;
}

.post-type {
    padding: 4px 10px;
    border-radius: 12px;
    font-weight: 600;
    font-size: 11px;
