}

.post-title {
    font-size: 20px;
    font-weight: 700;
    color: #333;
    margin-bottom: 12px;
}

.post-text {
    font-size: 15px;
    line-height: 1.6;
    color: #666;
    margin-bottom: 16px;
}

.post-image {
