    font-size: 14px;
}

.detail-item svg {
    width: 18px;
    height: 18px;
    color: #667eea;
}

.program-info {
    display: flex;
    flex-wrap: wrap;
    gap: 12px;
    margin-bottom: 16px;
}

.info-badge {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 8px 14px;
    background: #f5f7fa;
    border-radius: 20px;
    font-size: 13px;
    color: #666;
}

.info-badge svg {
    width: 16px;
    height: 16px;
    color: #667eea;
}

.view-details-btn {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 12px 24px;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
