.dropdown-item svg {
    width: 18px;
    height: 18px;
}

.dropdown-item:hover {
    background: #f5f7fa;
    color: #667eea;
}

.logout-btn {
    color: #f44336;
}

.logout-btn:hover {
    background: #ffebee;
    color: #d32f2f;
}

/* Main Dashboard */
.dashboard-main {
    padding: 24px;
    padding-top: 88px;
    height: 100vh;
    overflow: hidden;
}

.dashboard-container {
    max-width: 1400px;
    margin: 0 auto;
    display: grid;
    grid-template-columns: 1fr 360px;
    gap: 24px;
    height: calc(100vh - 112px); /* Full height minus navbar and padding */
}

/* Feed Section - Independent Scroll */
.feed-section {
    display: flex;
    flex-direction: column;
    gap: 20px;
    overflow-y: auto;
    overflow-x: hidden;
    height: 100%;
    padding-right: 8px;
}

/* Custom Scrollbar for Feed */
.feed-section::-webkit-scrollbar {
    width: 8px;
}

.feed-section::-webkit-scrollbar-track {
    background: rgba(241, 241, 241, 0.5);
    border-radius: 10px;
}

.feed-section::-webkit-scrollbar-thumb {
    background: rgba(102, 126, 234, 0.3);
    border-radius: 10px;
}

.feed-section::-webkit-scrollbar-thumb:hover {
    background: rgba(102, 126, 234, 0.5);
}

.feed-header h1 {
    font-size: 28px;
    color: #333;
    margin-bottom: 4px;
}

.feed-header p {
    color: #999;
    font-size: 14px;
}

/* Post Card */
.post-card {
    background: white;
    border-radius: 16px;
    padding: 24px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
    transition: box-shadow 0.3s ease;
    will-change: auto;
    transform: translateZ(0);
}

.post-card:hover {
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);
}

.post-header {
    display: flex;
    align-items: center;
    gap: 12px;
    margin-bottom: 16px;
}

.post-avatar {
    width: 48px;
    height: 48px;
    border-radius: 50%;
    object-fit: cover;
}

.post-info {
    flex: 1;
}

.post-author {
    font-size: 16px;
    font-weight: 600;
    color: #333;
    margin-bottom: 4px;
}

.post-meta {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 13px;
}

.post-type {
    padding: 4px 10px;
    border-radius: 12px;
    font-weight: 600;
    font-size: 11px;
    text-transform: uppercase;
}

.post-type.activity {
    background: #e8f5e9;
    color: #4CAF50;
}

.post-type.event {
    background: #fff3e0;
    color: #FF9800;
}

.post-type.announcement {
    background: #e3f2fd;
    color: #2196F3;
}

.post-type.program {
    background: #f3e5f5;
    color: #9C27B0;
}

.post-time {
    color: #999;
}

.post-content {
    margin-bottom: 16px;
}

.post-title {
    font-size: 20px;
    font-weight: 700;
    color: #333;
    margin-bottom: 12px;
}

.post-text {
    font-size: 15px;
    line-height: 1.6;
    color: #666;
    margin-bottom: 16px;
}

.post-image {
    border-radius: 12px;
    overflow: hidden;
    margin-bottom: 16px;
}

.post-image img {
    width: 100%;
    height: auto;
    display: block;
}

.post-details {
    display: flex;
    flex-wrap: wrap;
    gap: 16px;
    margin-bottom: 16px;
}

.detail-item {
    display: flex;
    align-items: center;
    gap: 8px;
    color: #666;
    font-size: 14px;
}

.detail-item svg {
    width: 18px;
    height: 18px;
    color: #667eea;
}

.program-info {
    display: flex;
    flex-wrap: wrap;
    gap: 12px;
    margin-bottom: 16px;
}

.info-badge {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 8px 14px;
    background: #f5f7fa;
    border-radius: 20px;
    font-size: 13px;
    color: #666;
}

.info-badge svg {
    width: 16px;
    height: 16px;
    color: #667eea;
}

.view-details-btn {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 12px 24px;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
    border: none;
    border-radius: 8px;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    transition: box-shadow 0.3s ease;
}

.view-details-btn:hover {
    box-shadow: 0 6px 20px rgba(102, 126, 234, 0.4);
}

.view-details-btn svg {
    width: 18px;
    height: 18px;
}

/* Post Actions */
.post-actions {
    display: flex;
    gap: 12px;
    padding-top: 16px;
    border-top: 1px solid #e0e0e0;
}

.action-btn {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    padding: 10px;
    background: none;
    border: none;
    border-radius: 8px;
    color: #666;
    font-size: 14px;
    font-weight: 500;
    cursor: pointer;
    transition: all 0.2s ease;
}

.action-btn svg {
    width: 18px;
    height: 18px;
}

.action-btn:hover {
    background: #f5f7fa;
    color: #667eea;
}

/* Comments Section */
.comments-section {
    margin-top: 16px;
    padding-top: 16px;
    border-top: 1px solid #e0e0e0;
}

.comment-item {
    display: flex;
    gap: 12px;
    margin-bottom: 16px;
}

.comment-item img {
    width: 36px;
    height: 36px;
    border-radius: 50%;
}

.comment-content {
    flex: 1;
    background: #f5f7fa;
    padding: 10px 14px;
    border-radius: 12px;
}

.comment-author {
    font-weight: 600;
    font-size: 13px;
    color: #333;
    margin-bottom: 4px;
}

.comment-text {
    font-size: 14px;
    color: #666;
    margin-bottom: 4px;
}

.comment-time {
    font-size: 12px;
    color: #999;
}

.comment-input-wrapper {
    display: flex;
    align-items: center;
    gap: 12px;
}

.comment-input-wrapper img {
    width: 36px;
    height: 36px;
    border-radius: 50%;
}

.comment-input {
    flex: 1;
    padding: 10px 14px;
    border: 2px solid #e0e0e0;
    border-radius: 20px;
    font-size: 14px;
    transition: all 0.3s ease;
}

.comment-input:focus {
    outline: none;
    border-color: #667eea;
}

.send-comment-btn {
    width: 36px;
    height: 36px;
    border: none;
    background: #667eea;
    border-radius: 50%;
    color: white;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.3s ease;
}

.send-comment-btn svg {
    width: 18px;
    height: 18px;
}

.send-comment-btn:hover {
    background: #5568d3;
}

/* Programs Sidebar - Independent Scroll */
.programs-sidebar {
    height: 100%;
    overflow-y: auto;
    overflow-x: hidden;
    padding-right: 8px;
}

/* Custom Scrollbar for Sidebar */
.programs-sidebar::-webkit-scrollbar {
    width: 8px;
}

.programs-sidebar::-webkit-scrollbar-track {
    background: rgba(241, 241, 241, 0.5);
    border-radius: 10px;
}

.programs-sidebar::-webkit-scrollbar-thumb {
    background: rgba(102, 126, 234, 0.3);
    border-radius: 10px;
}

.programs-sidebar::-webkit-scrollbar-thumb:hover {
    background: rgba(102, 126, 234, 0.5);
}

.sidebar-card {
    background: white;
    border-radius: 16px;
    padding: 24px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}

.sidebar-title {
    font-size: 20px;
    font-weight: 700;
    color: #333;
    margin-bottom: 4px;
}

.sidebar-subtitle {
    font-size: 13px;
    color: #999;
    margin-bottom: 20px;
}

.program-categories {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.program-category {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 14px;
    background: #f5f7fa;
    border-radius: 12px;
    cursor: pointer;
    transition: background 0.3s ease;
    will-change: auto;
}

.program-category:hover {
    background: #667eea;
}

.program-category:hover .category-content h3,
.program-category:hover .category-content p,
.program-category:hover .chevron {
    color: white;
}

.program-category:hover .category-icon {
    background: white;
}

/* Keep icon SVG color visible on hover */
.program-category:hover .category-icon svg {
    color: #667eea;
}

.category-icon {
    width: 44px;
    height: 44px;
    border-radius: 10px;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.3s ease;
}

.category-icon svg {
    width: 22px;
    height: 22px;
    color: white;
}

.category-icon.education {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
}

.category-icon.anti-drugs {
    background: linear-gradient(135deg, #f44336 0%, #e91e63 100%);
}

.category-icon.agriculture {
    background: linear-gradient(135deg, #4CAF50 0%, #8BC34A 100%);
}

.category-icon.disaster {
    background: linear-gradient(135deg, #FF9800 0%, #FF5722 100%);
}

.category-icon.sports {
    background: linear-gradient(135deg, #2196F3 0%, #03A9F4 100%);
}

.category-icon.gender {
    background: linear-gradient(135deg, #9C27B0 0%, #E91E63 100%);
}

.category-icon.health {
    background: linear-gradient(135deg, #f44336 0%, #FF5252 100%);
}

.category-icon.others {
    background: linear-gradient(135deg, #607D8B 0%, #455A64 100%);
}

.category-content {
    flex: 1;
}

.category-content h3 {
    font-size: 15px;
    font-weight: 600;
    color: #333;
    margin-bottom: 2px;
    transition: all 0.3s ease;
}

.category-content p {
    font-size: 12px;
    color: #999;
    transition: all 0.3s ease;
}

.chevron {
    width: 20px;
    height: 20px;
    color: #999;
    transition: all 0.3s ease;
}

/* Program Modal */
.program-modal {
    display: none;
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: 1000;
    align-items: center;
    justify-content: center;
}

.program-modal.active {
    display: flex;
}

.modal-overlay {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.5);
    backdrop-filter: blur(4px);
}

.modal-container {
    position: relative;
    background: white;
    border-radius: 20px;
    max-width: 600px;
    width: 90%;
    max-height: 90vh;
    overflow: hidden;
    display: flex;
    flex-direction: column;
    animation: modalSlideIn 0.3s ease;
}

.modal-container.large {
    max-width: 800px;
}

@keyframes modalSlideIn {
    from {
        opacity: 0;
        transform: scale(0.9) translateY(20px);
    }
    to {
        opacity: 1;
        transform: scale(1) translateY(0);
    }
}

.modal-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 24px;
    border-bottom: 1px solid #e0e0e0;
}

.modal-header h2 {
    font-size: 22px;
    color: #333;
}

.modal-close {
    width: 36px;
    height: 36px;
    border: none;
    background: #f5f7fa;
    border-radius: 50%;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.3s ease;
}

.modal-close svg {
    width: 20px;
    height: 20px;
    color: #666;
}

.modal-close:hover {
    background: #f44336;
}

.modal-close:hover svg {
    color: white;
}

.modal-body {
    padding: 24px;
    overflow-y: auto;
}

.program-item {
    padding: 20px;
    background: #f5f7fa;
    border-radius: 12px;
    margin-bottom: 16px;
}

.program-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 12px;
}

.program-header h3 {
    font-size: 18px;
    color: #333;
}

.program-status {
    padding: 6px 12px;
    border-radius: 12px;
    font-size: 12px;
    font-weight: 600;
}

.program-status.active {
    background: #e8f5e9;
    color: #4CAF50;
}

.program-description {
    font-size: 14px;
    color: #666;
    line-height: 1.6;
    margin-bottom: 12px;
}

.program-meta {
    display: flex;
    gap: 16px;
    font-size: 13px;
    color: #999;
    margin-bottom: 16px;
}

.apply-btn {
    padding: 10px 20px;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
    border: none;
    border-radius: 8px;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    transition: box-shadow 0.3s ease;
}

.apply-btn:hover {
    box-shadow: 0 6px 20px rgba(102, 126, 234, 0.4);
}

/* Scholarship Form */
.scholarship-form {
    display: flex;
    flex-direction: column;
    gap: 24px;
}

.form-section {
    display: flex;
    flex-direction: column;
    gap: 16px;
}

.form-section h3 {
    font-size: 18px;
    color: #333;
    padding-bottom: 8px;
    border-bottom: 2px solid #667eea;
}

.form-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 16px;
}

.form-group {
    display: flex;
    flex-direction: column;
    gap: 6px;
}

.form-group label {
    font-size: 14px;
    font-weight: 600;
    color: #333;
}

.form-group input,
.form-group select,
.form-group textarea {
    padding: 10px 14px;
    border: 2px solid #e0e0e0;
    border-radius: 8px;
    font-size: 14px;
    font-family: inherit;
    transition: all 0.3s ease;
}

.form-group input:focus,
.form-group select:focus,
.form-group textarea:focus {
    outline: none;
    border-color: #667eea;
    box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);
}

.form-actions {
    display: flex;
    gap: 12px;
    justify-content: flex-end;
    padding-top: 16px;
    border-top: 1px solid #e0e0e0;
}

.btn-primary,
.btn-secondary {
    padding: 12px 24px;
    border: none;
    border-radius: 8px;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s ease;
}

.btn-primary {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
}

.btn-primary:hover {
    box-shadow: 0 6px 20px rgba(102, 126, 234, 0.4);
}

.btn-secondary {
    background: #f5f7fa;
    color: #666;
}

.btn-secondary:hover {
    background: #e0e0e0;
}

/* Responsive Design */
@media (max-width: 1200px) {
    .dashboard-container {
        grid-template-columns: 1fr;
        height: auto;
    }

    .feed-section {
        height: auto;
        overflow-y: visible;
    }

    .dashboard-main {
        height: auto;
        overflow: visible;
    }

    body.youth-dashboard {
        overflow: auto;
        height: auto;
    }

    /* Show the Programs toggle button in navbar */
    .programs-drawer-btn {
        display: flex !important;
    }

    /* Sidebar becomes a fixed slide-in drawer */
    .programs-sidebar {
        position: fixed;
        top: 0;
        right: -380px;
        width: 340px;
        max-width: 90vw;
        height: 100vh;
        overflow-y: auto;
        padding: 0;
        z-index: 10000;
        transition: right 0.3s cubic-bezier(0.4, 0, 0.2, 1);
        box-shadow: -4px 0 24px rgba(2, 42, 84, 0.18);
    }

    .programs-sidebar.drawer-open {
        right: 0;
    }

    .programs-sidebar .sidebar-card {
        border-radius: 0;
        min-height: 100%;
        padding-top: 72px; /* space below navbar */
    }

    /* Backdrop */
    .programs-drawer-backdrop {
        display: none;
        position: fixed;
        inset: 0;
        background: rgba(0, 0, 0, 0.45);
        backdrop-filter: blur(2px);
        z-index: 9999;
    }

    .programs-drawer-backdrop.active {
        display: block;
    }
}

@media (max-width: 768px) {
    .navbar-center {
        flex: 1;
        min-width: 0;
        max-width: none;
    }

    .search-input {
        font-size: 13px;
        padding: 8px 12px 8px 38px;
    }

    .dashboard-main {
        padding: 16px;
        padding-top: 80px;
    }

    .post-card {
        padding: 16px;
    }

    .form-row {
        grid-template-columns: 1fr;
    }

    .modal-container {
        width: 95%;
    }
}

@media (max-width: 480px) {
    .navbar-title {
        display: none;
    }

    .navbar-right {
        gap: 8px;
    }

    .nav-icon-btn {
        width: 36px;
        height: 36px;
    }

    .feed-header h1 {
        font-size: 22px;
    }

    .post-title {
        font-size: 18px;
    }

    .post-actions {
        flex-direction: column;
    }
}

/* Alert Messages */
.alert {
    padding: 14px 18px;
    border-radius: 12px;
    margin-bottom: 20px;
    display: flex;
    align-items: center;
    font-size: 14px;
    animation: slideDown 0.3s ease;
}

@keyframes slideDown {
    from {
        opacity: 0;
        transform: translateY(-20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.alert-success {
    background: #e8f5e9;
    color: #2e7d32;
    border: 1px solid #4CAF50;
}

.alert svg {
    flex-shrink: 0;
}

/* ── Barangay Profiles ───────────────────────────────────────────────────── */
.barangay-profiles-list { display: flex; flex-direction: column; gap: 8px; }

.brgy-profile-item {
    display: flex; align-items: center; gap: 10px;
    padding: 10px 12px;
    background: #f5f7fa; border-radius: 12px;
    transition: background 0.2s ease;
    cursor: pointer;
}

.brgy-profile-item:hover { background: #eef1fb; }

.brgy-avatar {
    width: 40px; height: 40px; border-radius: 50%;
    display: flex; align-items: center; justify-content: center;
    font-size: 13px; font-weight: 800; color: #fff;
    flex-shrink: 0;
}

.brgy-info { flex: 1; min-width: 0; }

.brgy-name {
    font-size: 13px; font-weight: 700; color: #1a1d25;
    white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
}

.brgy-chair { font-size: 11px; color: #999; margin-top: 1px; }

/* Post author link */
.post-author-link {
    text-decoration: none;
    color: inherit;
    transition: color 0.2s ease;
}

.post-author-link:hover { color: #667eea; }

.post-header .post-author-link img {
    display: block;
    transition: opacity 0.2s ease;
}

.post-header .post-author-link:hover img { opacity: 0.85; }

