/* ── MAIN LAYOUT ── */
.dashboard-main {
    padding: 24px;
    padding-top: calc(var(--nav-h) + 24px);
    height: 100vh;
    overflow: hidden;
}

.dashboard-container {
    max-width: 1400px;
    margin: 0 auto;
    display: grid;
    grid-template-columns: 1fr 360px;
    gap: 24px;
    height: calc(100vh - var(--nav-h) - 48px);
}

/* ── FEED ── */
.feed-section {
    display: flex;
    flex-direction: column;
    gap: 16px;
    overflow-y: auto;
    overflow-x: hidden;
    height: 100%;
    padding-right: 6px;
}

.feed-section::-webkit-scrollbar { width: 6px; }
.feed-section::-webkit-scrollbar-track { background: transparent; }
.feed-section::-webkit-scrollbar-thumb { background: var(--border); border-radius: 6px; }
.feed-section::-webkit-scrollbar-thumb:hover { background: #cbd5e1; }

.feed-header h1 {
    font-size: 22px;
    font-weight: 800;
    color: var(--text-primary);
    margin-bottom: 2px;
    letter-spacing: -0.02em;
}

.feed-header p { color: var(--text-muted); font-size: 13px; }

/* ── POST CARD ── */
.post-card {
    background: var(--surface);
    border-radius: var(--radius-md);
    padding: 20px;
    box-shadow: var(--shadow-sm);
    border: 1px solid var(--border);
    transition: box-shadow 0.2s, border-color 0.2s;
}

.post-card:hover {
    box-shadow: var(--shadow-md);
    border-color: #cbd5e1;
}

.post-header {
    display: flex;
    align-items: center;
    gap: 12px;
    margin-bottom: 14px;
}

.post-avatar {
    width: 44px;
    height: 44px;
    border-radius: 50%;
    object-fit: cover;
}

.post-info { flex: 1; }

.post-author {
    font-size: 15px;
    font-weight: 700;
    color: var(--text-primary);
    margin-bottom: 3px;
}

.post-meta {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 12px;
}

.post-type {
    padding: 3px 9px;
    border-radius: 20px;
    font-weight: 700;
    font-size: 10px;
    text-transform: uppercase;
    letter-spacing: 0.04em;
}

.post-type.activity    { background: #dcfce7; color: #15803d; }
