/* ── RESPONSIVE ── */
@media (max-width: 1200px) {
    .dashboard-container { grid-template-columns: 1fr; height: auto; }
    .feed-section { height: auto; overflow-y: visible; }
    .dashboard-main { height: auto; overflow: visible; }
    body.youth-dashboard { overflow: auto; height: auto; }
    .programs-drawer-btn { display: flex !important; }

    .programs-sidebar {
        position: fixed;
        top: 0; right: -380px;
        width: 340px; max-width: 90vw;
        height: 100vh;
        overflow-y: auto;
        padding: 0;
        z-index: 10000;
        transition: right 0.3s cubic-bezier(0.4,0,0.2,1);
        box-shadow: -4px 0 24px rgba(2,42,84,0.18);
    }

    .programs-sidebar.drawer-open { right: 0; }
    .programs-sidebar .sidebar-card { border-radius: 0; min-height: 100%; padding-top: 80px; }

    .programs-drawer-backdrop {
        display: none;
        position: fixed; inset: 0;
        background: rgba(0,0,0,0.45);
        backdrop-filter: blur(2px);
        z-index: 9999;
    }

    .programs-drawer-backdrop.active { display: block; }
}

@media (max-width: 768px) {
    .navbar-center { flex: 1; min-width: 0; max-width: none; }
    .search-input { font-size: 13px; padding: 8px 12px 8px 38px; }
    .dashboard-main { padding: 14px; padding-top: calc(var(--nav-h) + 14px); }
    .post-card { padding: 16px; }
    .form-row { grid-template-columns: 1fr; }
    .modal-container { width: 95%; }
}

@media (max-width: 480px) {
    .navbar-title small { display: none; }
    .navbar-right { gap: 6px; }
    .nav-icon-btn { width: 34px; height: 34px; }
    .feed-header h1 { font-size: 18px; }
    .post-title { font-size: 15px; }
    .post-actions { flex-direction: column; }
}

/* ── ALERTS ── */
.alert {
    padding: 12px 16px;
    border-radius: var(--radius-sm);
    margin-bottom: 16px;
    display: flex;
    align-items: center;
    font-size: 13px;
    animation: slideDown 0.25s ease;
}

@keyframes slideDown {
    from { opacity: 0; transform: translateY(-16px); }
    to   { opacity: 1; transform: translateY(0); }
}

.alert-success { background: #f0fdf4; color: #15803d; border: 1px solid #bbf7d0; }

/* ── BARANGAY PROFILES ── */
.barangay-profiles-list { display: flex; flex-direction: column; gap: 6px; }

.brgy-profile-item {
    display: flex; align-items: center; gap: 10px;
    padding: 9px 11px;
    background: var(--bg);
    border-radius: var(--radius-sm);
    border: 1px solid transparent;
    transition: background 0.15s, border-color 0.15s;
    cursor: pointer;
}

.brgy-profile-item:hover { background: #eff6ff; border-color: #bfdbfe; }

.brgy-avatar {
    width: 36px; height: 36px; border-radius: 50%;
    display: flex; align-items: center; justify-content: center;
    font-size: 12px; font-weight: 800; color: white; flex-shrink: 0;
}

.brgy-info { flex: 1; min-width: 0; }
.brgy-name { font-size: 13px; font-weight: 700; color: var(--text-primary); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.brgy-chair { font-size: 11px; color: var(--text-muted); margin-top: 1px; }

/* ── POST AUTHOR LINK ── */
.post-author-link { text-decoration: none; color: inherit; transition: color 0.15s; }
.post-author-link:hover { color: var(--brand-mid); }
.post-header .post-author-link img { display: block; transition: opacity 0.15s; }
.post-header .post-author-link:hover img { opacity: 0.85; }

