function previewImage(input){var file=input.files[0];if(!file)return;var reader=new FileReader();reader.onload=function(e){pendingImageDataUrl=e.target.result;document.getElementById('compose-preview-img').src=e.target.result;document.getElementById('compose-image-preview').style.display='block';};reader.readAsDataURL(file);
// Upload to Cloudinary
var fd=new FormData();fd.append('image',file);fd.append('_token',document.querySelector('meta[name="csrf-token"]').content);
fetch('/announcements/upload-image',{method:'POST',body:fd}).then(function(r){return r.json();}).then(function(d){if(d.url){pendingImageDataUrl=d.url;document.getElementById('compose-preview-img').src=d.url;}}).catch(function(){});}

